uick_desc:"8 questions · ~3 minutes · Orientation générale",test_medium_desc:"24 questions · ~10 minutes · Profil fiable",test_full_desc:"40 questions · ~20 minutes · Précision maximale",test_start:"Commencer le test",test_note:"Les tests plus longs produisent des profils plus précis. Vous pouvez toujours ajouter des questions plus tard.",priorities_title:"Quels sujets vous tiennent le plus à cœur ?",priorities_subtitle:"Classez les thèmes du plus au moins important. Cela influence la pondération de votre profil.",priorities_most:"Le plus important",priorities_least:"Le moins important",priorities_confirm:"Confirmer et commencer",priorities_skip:"Pondération égale",q_progress:"Question {current} sur {total}",q_skip:"Passer cette question",q_next:"Suivant",q_prev:"Précédent",q_finish:"Voir mon profil",q_answer_1:"Pas du tout d'accord",q_answer_2:"Pas d'accord",q_answer_3:"Neutre",q_answer_4:"D'accord",q_answer_5:"Tout à fait d'accord",q_learn_more:"En savoir plus",q_theme_label:"Thème :",profile_title:"Votre profil politique",profile_subtitle:"Sur la base de vos réponses, voici votre profil politique multidimensionnel.",profile_themes_title:"Profil par thème",profile_axes_title:"Axes idéologiques",profile_refine:"Affiner mon profil",profile_refine_add:"Ajouter {n} questions",profile_export:"Exporter le profil (JSON)",profile_import:"Importer un profil",profile_reset:"Réinitialiser le profil",profile_reset_confirm:"Réinitialiser votre profil ? Cela effacera toutes vos réponses.",profile_answered:"{n} questions répondues",profile_of_total:"sur {total}",profile_view_elections:"Comparer avec les élections",profile_view_figures:"Comparer avec les figures historiques",profile_axis_economic:"Axe économique",profile_axis_social:"Axe social",profile_axis_institutional:"Axe institutionnel",profile_axis_international:"Axe international",elections_title:"Compatibilité électorale",elections_subtitle:"Découvrez comment votre profil s'aligne avec des candidats et des partis réels."